server.js
import express from 'express';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';
import morgan from 'morgan';
import dotenv from 'dotenv';
import { z } from 'zod';
import bcrypt from 'bcrypt';
import Database from 'better-sqlite3';
import crypto from 'crypto';
import { v4 as uuidv4 } from 'uuid';
import cookieParser from 'cookie-parser';
import { doubleCsrf } from 'csrf-csrf';

dotenv.config();

const app = express();
app.use(helmet({
  contentSecurityPolicy: false
}));
app.use(express.json({ limit: '10kb' }));
app.use(cookieParser());
app.use(morgan('combined'));

const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 60,
  standardHeaders: true,
  legacyHeaders: false
});
app.use(limiter);

// CSRF protection for form‑based routes (if you serve HTML forms)
const {
  doubleCsrfProtection,
  generateToken
} = doubleCsrf({
  getSecret: () => process.env.API_KEY || 'dev-secret',
  cookieName: 'csrf-token',
  cookieOptions: {
    sameSite: 'lax',
    httpOnly: true,
    secure: true
  },
  size: 64
});

// Init DB
const db = new Database('data.db');
db.pragma('journal_mode = WAL');
db.exec(`
  CREATE TABLE IF NOT EXISTS records (
    id TEXT PRIMARY KEY,
    purpose TEXT NOT NULL,
    consent BOOLEAN NOT NULL,
    email_cipher TEXT,
    email_iv TEXT,
    email_tag TEXT,
    name_cipher TEXT,
    name_iv TEXT,
    name_tag TEXT,
    phone_cipher TEXT,
    phone_iv TEXT,
    phone_tag TEXT,
    password_hash TEXT,
    created_at INTEGER NOT NULL
  );

  CREATE TABLE IF NOT EXISTS audit (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    record_id TEXT,
    action TEXT,
    actor TEXT,
    ts INTEGER NOT NULL
  );
`);

function getKey() {
  const b64 = process.env.DATA_KEY_BASE64;
  if (!b64) throw new Error('DATA_KEY_BASE64 missing');
  const key = Buffer.from(b64, 'base64');
  if (key.length !== 32) throw new Error('DATA_KEY_BASE64 must decode to 32 bytes');
  return key;
}

function encryptField(plain) {
  if (plain == null) return { cipher: null, iv: null, tag: null };
  const key = getKey();
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
  const ct = Buffer.concat([cipher.update(String(plain), 'utf8'), cipher.final()]);
  const tag = cipher.getAuthTag();
  return {
    cipher: ct.toString('base64'),
    iv: iv.toString('base64'),
    tag: tag.toString('base64')
  };
}

function decryptField(cipher, iv, tag) {
  if (!cipher || !iv || !tag) return null;
  const key = getKey();
  const ivBuf = Buffer.from(iv, 'base64');
  const tagBuf = Buffer.from(tag, 'base64');
  const decipher = crypto.createDecipheriv('aes-256-gcm', key, ivBuf);
  decipher.setAuthTag(tagBuf);
  const pt = Buffer.concat([decipher.update(Buffer.from(cipher, 'base64')), decipher.final()]);
  return pt.toString('utf8');
}

const recordSchema = z.object({
  purpose: z.string().min(5).max(200),
  consent: z.boolean().refine(val => val === true, { message: 'Consent required' }),
  email: z.string().email().optional(),
  name: z.string().min(1).max(200).optional(),
  phone: z.string().regex(/^[0-9+\-() ]{7,20}$/).optional(),
  password: z.string().min(10).max(128).optional()
});

function requireApiKey(req, res, next) {
  const key = req.header('X-API-Key');
  if (!key || key !== process.env.API_KEY) {
    return res.status(403).json({ error: 'forbidden' });
  }
  next();
}

// Example HTML form (served for demo)
app.get('/form', (req, res) => {
  const token = generateToken(req, res);
  res.type('html').send(`
