Pseudo-code: listing creation with moderation
import { Request, Response } from 'express';
import { z } from 'zod';

const listingSchema = z.object({
  title: z.string().min(5).max(120),
  description: z.string().min(20).max(5000),
  priceCents: z.number().int().positive(),
  currency: z.enum(['USD','EUR','GBP']),
  quantity: z.number().int().positive(),
  categoryId: z.string(),
  imageUrls: z.array(z.string().url()).max(10)
});

const bannedKeywords = [
  // maintainable policy-driven list loaded from DB/config
  'prohibited_term_1','prohibited_term_2','restricted_item_code'
];

function textSignals(text: string) {
  const t = text.toLowerCase();
  return bannedKeywords.filter(k => t.includes(k));
}

async function moderateImages(urls: string[]) {
  // call image moderation provider; return any flags
  return [];
}

export async function createListing(req: Request, res: Response) {
  const parse = listingSchema.safeParse(req.body);
  if (!parse.success) { return res.status(400).json({ error: 'Invalid payload' }); }
  const user = req.user;
  if (!user || user.role !== 'seller' || user.kyc_status !== 'approved') {
    return res.status(403).json({ error: 'Seller onboarding required' });
  }
  const { title, description, imageUrls } = parse.data;

  const signals = [
    ...textSignals(title),
    ...textSignals(description),
    ...(await moderateImages(imageUrls))
  ];
  const moderation_state = signals.length ? 'pending' : 'approved';

  const listing = await db.listings.insert({
    seller_id: user.id,
    ...parse.data,
    status: moderation_state === 'approved' ? 'active' : 'draft',
    moderation_state
  });

  if (moderation_state === 'pending') {
    await db.moderation_queue.insert({
      subject_type: 'listing',
      subject_id: listing.id,
      reason: 'auto-signals',
      signals: signals,
      state: 'pending'
    });
  }

  return res.json({ listing });
}

