Example message filter
const forbiddenPhrases = ['harassment_phrase', 'scam_pattern'];
function sanitizeMessage(body: string) {
  const lower = body.toLowerCase();
  const hit = forbiddenPhrases.find(p => lower.includes(p));
  if (hit) { return { allowed: false, reason: 'policy_violation' }; }
  return { allowed: true, body: body.trim() };
}

