Example defensive script: monitor Linux authentication logs for brute-force patterns and alert when a threshold is exceeded.

Python (reads /var/log/auth.log, aggregates failed SSH logins per source IP, and prints alerts):
- Requirements: Python 3, read access to /var/log/auth.log
- Note: Run with sufficient privileges to read auth.log

Code:
import re
import time
from collections import defaultdict, deque
from datetime import datetime, timedelta

AUTH_LOG = "/var/log/auth.log"
FAILED_RE = re.compile(r"Failed password for (?:invalid user )?\S+ from (\d+\.\d+\.\d+\.\d+) port \d+")
THRESHOLD = 10           # number of failed attempts
WINDOW_SEC = 300         # time window in seconds (5 minutes)
CHECK_INTERVAL = 2.0     # seconds between reads

def follow(path):
    with open(path, "r", errors="ignore") as f:
        f.seek(0, 2)
        while True:
            line = f.readline()
            if not line:
                time.sleep(CHECK_INTERVAL)
                continue
            yield line

def now():
    return datetime.utcnow()

def main():
    failures = defaultdict(deque)  # IP -> deque of timestamps
    for line in follow(AUTH_LOG):
        m = FAILED_RE.search(line)
        if not m:
            continue
        ip = m.group(1)
        t = now()
        dq = failures[ip]
        dq.append(t)
        # Evict entries outside the window
        cutoff = t - timedelta(seconds=WINDOW_SEC)
        while dq and dq[0] < cutoff:
            dq.popleft()
        if len(dq) >= THRESHOLD:
            print(f"[ALERT] Possible brute-force from {ip}: {len(dq)} failures in {WINDOW_SEC}s at {t.isoformat()}")

if __name__ == "__main__":
    main()

Example defensive script: simple file integrity monitor for critical directories (hash-based baseline + alert on changes).

Python:
- Set MONITOR_DIRS to directories you control and wish to monitor
- First run builds a baseline; subsequent runs detect changes

import os
import sys
import json
import time
import hashlib

MONITOR_DIRS = ["/etc", "/usr/local/bin"]  # adjust to your environment
BASELINE_PATH = "/var/tmp/file_baseline.json"
SCAN_INTERVAL = 30  # seconds

def sha256_file(path):
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return h.hexdigest()

def snapshot(dirs):
    data = {}
    for d in dirs:
        for root, _, files in os.walk(d):
            for name in files:
                p = os.path.join(root, name)
                try:
                    data[p] = {
                        "hash": sha256_file(p),
                        "mtime": os.path.getmtime(p),
                        "size": os.path.getsize(p),
                    }
                except (PermissionError, FileNotFoundError, IsADirectoryError):
                    continue
    return data

def load_baseline():
    if not os.path.exists(BASELINE_PATH):
        return {}
    with open(BASELINE_PATH, "r") as f:
        return json.load(f)

def save_baseline(data):
    with open(BASELINE_PATH, "w") as f:
        json.dump(data, f, indent=2, sort_keys=True)

def diff(baseline, current):
    added = [p for p in current.keys() if p not in baseline]
    removed = [p for p in baseline.keys() if p not in current]
    modified = []
    for p in current.keys() & baseline.keys():
        if current[p]["hash"] != baseline[p]["hash"]:
            modified.append(p)
    return added, removed, modified

def main():
    baseline = load_baseline()
    if not baseline:
        print("Building baseline...")
        baseline = snapshot(MONITOR_DIRS)
        save_baseline(baseline)
        print(f"Baseline saved to {BASELINE_PATH} ({len(baseline)} files)")
    while True:
        current = snapshot(MONITOR_DIRS)
        added, removed, modified = diff(baseline, current)
        for p in added:
            print(f"[ALERT] New file: {p}")
        for p in removed:
            print(f"[ALERT] File removed: {p}")
        for p in modified:
            print(f"[ALERT] File modified: {p}")
        baseline = current
        save_baseline(baseline)
        time.sleep(SCAN_INTERVAL)

