script.js
const questions = [
  {
    q: "A text says your card will be frozen unless you share an OTP. What should you do?",
    options: [
      "Share the OTP to keep your card active",
      "Ignore the message and call the number on your card",
      "Reply asking for more details"
    ],
    correctIndex: 1,
    explain: "Never share OTPs. Contact your card issuer using official channels."
  },
  {
    q: "You’re about to pay on a site that shows 'Not Secure' in the browser. Best action?",
    options: [
      "Proceed quickly to finish the purchase",
      "Switch to a trusted site with HTTPS",
      "Email your card number to the seller"
    ],
    correctIndex: 1,
    explain: "Use secure sites (HTTPS) and reputable payment gateways."
  },
  {
    q: "At an ATM, the card slot feels loose and bulky. What’s wise?",
    options: [
      "Use it anyway—time is tight",
      "Try another ATM and notify the bank",
      "Pull harder until it’s snug"
    ],
    correctIndex: 1,
    explain: "It could be a skimmer. Use another machine and report it."
  },
  {
    q: "You see a small unfamiliar charge from an online store.",
    options: [
      "Wait to see if it goes away",
      "Dispute the transaction and check recent orders",
      "Post your card details in a forum for help"
    ],
    correctIndex: 1,
    explain: "Dispute immediately and review recent transactions and subscriptions."
  }
];

function renderQuiz() {
  const container = document.getElementById("quiz-container");
  questions.forEach((item, i) => {
    const block = document.createElement("div");
    block.className = "quiz-item";
    const q = document.createElement("p");
    q.textContent = `${i + 1}. ${item.q}`;
    block.appendChild(q);

    item.options.forEach((opt, j) => {
      const label = document.createElement("label");
      label.style.display = "block";
      const input = document.createElement("input");
      input.type = "radio";
      input.name = `q${i}`;
      input.value = j;
      label.appendChild(input);
      label.append(` ${opt}`);
      block.appendChild(label);
    });
    container.appendChild(block);
  });
}
renderQuiz();

document.getElementById("submit-quiz").addEventListener("click", () => {
  let score = 0;
  let answered = 0;
  questions.forEach((item, i) => {
    const selected = document.querySelector(`input[name="q${i}"]:checked`);
    if (selected) {
      answered++;
      if (Number(selected.value) === item.correctIndex) score++;
    }
  });
  const result = document.getElementById("quiz-result");
  if (answered < questions.length) {
    result.textContent = "Please answer all questions.";
    result.style.color = "var(--bad)";
    return;
  }
  const percent = Math.round((score / questions.length) * 100);
  result.textContent = `Your score: ${score}/${questions.length} (${percent}%).`;
  result.style.color = percent >= 75 ? "var(--good)" : "var(--bad)";
  if (percent < 75) {
    const firstMissed = questions.find((item, i) => {
      const selected = document.querySelector(`input[name="q${i}"]:checked`);
      return Number(selected.value) !== item.correctIndex;
    });
    if (firstMissed) {
      result.textContent += ` Tip: ${firstMissed.explain}`;
    }
  }
});

