:root {
  --bg: #0f172a;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --brand: #60a5fa;
  --accent: #34d399;
  --danger: #f87171;
  --card: #1f2937;
  --border: #374151;
}
* { box-sizing: border-box; }
html, body { margin: 0; padding: 0; background: var(--bg); color: var(--text); font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; }
.site-header, .site-footer { display: flex; align-items: center; justify-content: space-between; padding: 1rem 1.25rem; background: var(--panel); border-bottom: 1px solid var(--border); }
.site-footer { border-top: 1px solid var(--border); }
.brand { display: flex; align-items: center; gap: 0.5rem; }
.logo { width: 28px; height: 28px; }
.brand-name { font-weight: 700; letter-spacing: 0.2px; }
.nav { display: flex; gap: 0.5rem; flex-wrap: wrap; }
.nav-link { background: transparent; border: 1px solid var(--border); color: var(--text); padding: 0.5rem 0.75rem; border-radius: 8px; cursor: pointer; }
.nav-link:hover { border-color: var(--brand); color: var(--brand); }
main { max-width: 1100px; margin: 0 auto; padding: 1rem; }
.route { display: none; }
.route.active { display: block; }
.grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1rem; }
.card { background: var(--card); padding: 1rem; border: 1px solid var(--border); border-radius: 12px; }
h1, h2, h3 { margin: 0.25rem 0 0.75rem; }
p, li { color: var(--text); line-height: 1.6; }
label { display: block; margin: 0.5rem 0; color: var(--muted); }
textarea { width: 100%; padding: 0.75rem; border-radius: 8px; border: 1px solid var(--border); background: #0b1220; color: var(--text); }
.checklist { margin: 0.75rem 0; display: grid; gap: 0.5rem; }
.check-item { display: grid; grid-template-columns: 22px 1fr; align-items: start; gap: 0.5rem; }
input[type="checkbox"] { width: 18px; height: 18px; }
button { background: var(--brand); color: #0b1220; border: none; padding: 0.6rem 0.9rem; border-radius: 8px; cursor: pointer; }
button:hover { filter: brightness(1.1); }
.result { margin-top: 0.75rem; padding: 0.75rem; border-radius: 8px; background: #0b1220; border: 1px solid var(--border); }
.case-list { display: grid; gap: 0.75rem; }
.case-item { background: var(--card); border: 1px solid var(--border); border-radius: 10px; padding: 0.75rem; cursor: pointer; }
.case-item:hover { border-color: var(--brand); }
.case-detail { background: var(--card); border: 1px solid var(--border); border-radius: 10px; padding: 1rem; }
.tools, .pitfalls { margin: 0; padding-left: 1.25rem; }
@media (prefers-color-scheme: light) {
  :root { --bg: #f8fafc; --panel: #f1f5f9; --text: #0f172a; --muted: #334155; --card: #ffffff; --border: #e5e7eb; }
  button { color: #fff; }
}

script.js (paste as-is)
// Simple client-side router
const routes = Array.from(document.querySelectorAll('.route'));
const navLinks = Array.from(document.querySelectorAll('.nav-link'));
navLinks.forEach(btn => btn.addEventListener('click', () => showRoute(btn.dataset.route)));
function showRoute(routeId) {
  routes.forEach(r => r.classList.remove('active'));
  document.getElementById(routeId).classList.add('active');
}
// Default route
showRoute('home');

// Claim evaluation
document.getElementById('evaluate-btn').addEventListener('click', () => {
  const claim = document.getElementById('claim-input').value.trim();
  const checks = [
    { id: 'source-check', label: 'Primary source' },
    { id: 'context-check', label: 'Context provided' },
    { id: 'expert-check', label: 'Expert consensus' },
    { id: 'corroboration-check', label: 'Independent corroboration' },
    { id: 'pattern-check', label: 'Red flags' }
  ];
  const status = checks.map(c => ({ label: c.label, value: document.getElementById(c.id).checked }));
  const score = status.filter(s => s.value).length;
  const resultEl = document.getElementById('evaluation-result');

  let summary = '';
  if (score >= 4) {
    summary = 'This claim shows multiple signs of strong support. Review sources directly before sharing.';
  } else if (score === 2 || score === 3) {
    summary = 'Mixed indicators. Seek primary materials and expert consensus.';
  } else {
    summary = 'Low support indicators. Be cautious, look for original sources and context.';
  }
  const detail = status.map(s => `• ${s.label}: ${s.value ? 'Yes' : 'No'}`).join('\n');

  resultEl.textContent = (claim ? `Claim: ${claim}\n` : '') + summary + '\n' + detail;
});

// Load case studies and resources
async function loadJSON(path) {
  const res = await fetch(path);
  return res.json();
}
async function initData() {
  const cases = await loadJSON('data/case-studies.json');
  const caseList = document.getElementById('case-list');
  const caseDetail = document.getElementById('case-detail');

  cases.forEach(c => {
    const item = document.createElement('div');
    item.className = 'case-item';
    item.innerHTML = `<h3>${c.title}</h3><p>${c.summary}</p><p class="muted">Read walkthrough</p>`;
    item.addEventListener('click', () => {
      caseDetail.hidden = false;
      caseDetail.innerHTML = `
        <h2>${c.title}</h2>
        <p><strong>Claim:</strong> ${c.claim}</p>
        <p><strong>Origin:</strong> ${c.origin}</p>
        <h3>Evidence</h3>
        <ul>${c.evidence.map(e => `<li><a href="${e.link}" target="_blank" rel="noopener">${e.label}</a> — ${e.note}</li>`).join('')}</ul>
        <h3>Red Flags</h3>
        <ul>${c.redFlags.map(r => `<li>${r}</li>`).join('')}</ul>
        <h3>Conclusion</h3>
        <p>${c.conclusion}</p>
      `;
      showRoute('cases');
    });
    caseList.appendChild(item);
  });

  const resources = await loadJSON('data/resources.json');
  const resList = document.getElementById('resource-list');
  resources.forEach(r => {
    const li = document.createElement('div');
    li.className = 'case-item';
    li.innerHTML = `<h3><a href="${r.link}" target="_blank" rel="noopener">${r.name}</a></h3><p>${r.desc}</p>`;
    resList.appendChild(li);
  });
}
initData();

