Example: a simple Python permission-auditing script you can run on systems you own or are authorized to assess. It flags world-readable/writable files and a risky SSH setting.

#!/usr/bin/env python3
import os
import sys
import stat
from pathlib import Path

def check_file_perms(root_path: Path, sensitive_names=("secret", "confidential", "private")):
    issues = []
    for dirpath, _, filenames in os.walk(root_path, followlinks=False):
        d = Path(dirpath)
        for name in filenames:
            p = d / name
            try:
                st = p.lstat()
            except (FileNotFoundError, PermissionError):
                continue
            mode = st.st_mode
            world_read = bool(mode & stat.S_IROTH)
            world_write = bool(mode & stat.S_IWOTH)
            is_sensitive = any(s in p.name.lower() or s in str(p.parent).lower() for s in sensitive_names)
            if world_write or (world_read and is_sensitive):
                issues.append((str(p), oct(mode & 0o777)))
    return issues

def check_sshd_config(path="/etc/ssh/sshd_config"):
    risky = []
    try:
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            for line in f:
                s = line.strip()
                if not s or s.startswith("#"):
                    continue
                if s.lower().startswith("permitrootlogin"):
                    parts = s.split()
                    if len(parts) > 1 and parts[1].lower() in ("yes", "prohibit-password"):
                        risky.append(("PermitRootLogin", parts[1]))
                if s.lower().startswith("passwordauthentication"):
                    parts = s.split()
                    if len(parts) > 1 and parts[1].lower() == "yes":
                        risky.append(("PasswordAuthentication", parts[1]))
    except FileNotFoundError:
        pass
    return risky

def main():
    targets = [Path(p) for p in (sys.argv[1:] or ["."])]
    all_issues = []
    for t in targets:
        if t.exists():
            all_issues.extend(check_file_perms(t))
    ssh_issues = check_sshd_config()

    if not all_issues and not ssh_issues:
        print("No obvious risky permissions or SSH settings found.")
        return

    if all_issues:
        print("World-accessible file findings:")
        for p, mode in all_issues:
            print(f"  {p} has mode {mode}")
        print("Suggested remediation: tighten permissions (e.g., chmod 640/600), restrict group membership, and segregate sensitive data paths.")

    if ssh_issues:
        print("Risky SSH configuration settings:")
        for k, v in ssh_issues:
            print(f"  {k} {v}")
        print("Suggested remediation: set PermitRootLogin no and PasswordAuthentication no (use keys + MFA). Restart sshd after changes.")

if __name__ == "__main__":
    main()

