Example defensive script (Python) that baselines and monitors processes and network connections, flagging suspicious heuristics and logging findings to JSON. Run on systems you own or are authorized to assess.

Requires: Python 3.9+, psutil (pip install psutil)

"""
monitor_security.py
Behavior:
- Baselines current process executable paths (once) and stores them in baseline_binaries.json
- On each cycle:
  - Scans processes and their network connections
  - Flags binaries running from temp/downloads directories
  - Flags outbound connections to public IPs on uncommon high-risk ports
  - Flags listening services bound to 0.0.0.0 on uncommon ports
  - Flags binaries not present in the baseline
  - Optionally checks IPs against a local blocklist file (blocklist.txt), one IP or CIDR per line
- Writes detailed findings to findings.json and prints a concise summary
"""

import json
import os
import time
import psutil
import ipaddress
import socket
import tempfile
from datetime import datetime

BASELINE_FILE = "baseline_binaries.json"
FINDINGS_FILE = "findings.json"
BLOCKLIST_FILE = "blocklist.txt"

SCAN_INTERVAL_SECONDS = 10

# Ports commonly abused by remote shells / unauthorized services (example list; adjust for your environment)
SUSPICIOUS_PORTS = {4444, 5555, 1337, 9001, 31337}

def load_baseline():
    if os.path.exists(BASELINE_FILE):
        with open(BASELINE_FILE, "r", encoding="utf-8") as f:
            try:
                return set(json.load(f))
            except Exception:
                return set()
    return set()

def save_baseline(paths_set):
    with open(BASELINE_FILE, "w", encoding="utf-8") as f:
        json.dump(sorted(list(paths_set)), f, indent=2)

def load_blocklist():
    nets = []
    if os.path.exists(BLOCKLIST_FILE):
        with open(BLOCKLIST_FILE, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                try:
                    # Allow both single IP and CIDR
                    if "/" in line:
                        nets.append(ipaddress.ip_network(line, strict=False))
                    else:
                        nets.append(ipaddress.ip_network(line + "/32", strict=False))
                except ValueError:
                    pass
    return nets

def ip_in_blocklist(ip, nets):
    try:
        addr = ipaddress.ip_address(ip)
        for net in nets:
            if addr in net:
                return True
        return False
    except ValueError:
        return False

def is_public_ip(ip):
    try:
        addr = ipaddress.ip_address(ip)
        return not (addr.is_private or addr.is_loopback or addr.is_link_local or addr.is_reserved or addr.is_multicast)
    except ValueError:
        return False

def get_suspicious_dirs():
    dirs = set()
    # Cross-platform suspicious locations where long-running binaries are unusual
    dirs.add(os.path.join(tempfile.gettempdir()))
    dirs.add(os.path.expanduser("~/Downloads"))
    # Windows-specific additions
    appdata = os.environ.get("APPDATA")
    localappdata = os.environ.get("LOCALAPPDATA")
    if appdata:
        dirs.add(appdata)
    if localappdata:
        dirs.add(localappdata)
    return {os.path.abspath(d) for d in dirs if d}

def path_in_dirs(path, dirs):
    try:
        ap = os.path.abspath(path)
        for d in dirs:
            # Ensure directory exists before checking
            if os.path.isdir(d):
                try:
                    # Common prefix check; handle case-insensitive Windows paths
                    if os.name == "nt":
                        if ap.lower().startswith(d.lower()):
                            return True
                    else:
                        if ap.startswith(d):
                            return True
                except Exception:
                    continue
        return False
    except Exception:
        return False

def collect_baseline_paths():
    paths = set()
    for proc in psutil.process_iter(attrs=["pid", "name", "exe"]):
        info = proc.info
        exe = info.get("exe") or ""
        if exe and os.path.exists(exe):
            paths.add(exe)
    return paths

def summarize_connection(conn):
    try:
        laddr = f"{conn.laddr.ip}:{conn.laddr.port}" if conn.laddr else ""
    except Exception:
        laddr = ""
    try:
        raddr = f"{conn.raddr.ip}:{conn.raddr.port}" if conn.raddr else ""
    except Exception:
        raddr = ""
    return {"laddr": laddr, "raddr": raddr, "status": getattr(conn, "status", "")}

def monitor_cycle(baseline_paths, blocknets, suspicious_dirs):
    findings = []
    ts = datetime.utcnow().isoformat() + "Z"

    for proc in psutil.process_iter(attrs=["pid", "name", "exe", "username"]):
        info = proc.info
        pid = info.get("pid")
        name = info.get("name") or ""
        exe = info.get("exe") or ""
        user = info.get("username") or ""

        proc_findings = []

        # Heuristic: binary in temp/downloads/appdata directories
        if exe and path_in_dirs(exe, suspicious_dirs):
            proc_findings.append({"type": "binary_location", "detail": f"Executable in suspicious directory: {exe}"})

        # Heuristic: binary not in baseline
        if exe and exe not in baseline_paths:
            proc_findings.append({"type": "new_binary", "detail": f"Executable not in baseline: {exe}"})

        # Network checks
        try:
            conns = proc.connections(kind="inet")
        except (psutil.AccessDenied, psutil.NoSuchProcess):
            conns = []
        except Exception:
            conns = []

        for c in conns:
            # Outbound
            if c.raddr and c.raddr.ip:
                rip = c.raddr.ip
                rport = c.raddr.port
                # Heuristic: outbound to public IP on suspicious ports
                if is_public_ip(rip) and rport in SUSPICIOUS_PORTS:
                    proc_findings.append({
                        "type": "suspicious_outbound_port",
                        "detail": f"Outbound to {rip}:{rport} on high-risk port"
                    })
                # Blocklist check
                if ip_in_blocklist(rip, blocknets):
                    proc_findings.append({
                        "type": "blocklist_hit",
                        "detail": f"Outbound connection to blocked IP/network: {rip}"
                    })
            # Listening services
            if c.laddr and c.laddr.ip and c.status == psutil.CONN_LISTEN:
                lip = c.laddr.ip
                lport = c.laddr.port
                # Heuristic: listening on all interfaces and uncommon ports
                if lip in ("0.0.0.0", "::"):
                    if lport in SUSPICIOUS_PORTS or lport >= 1024:
                        proc_findings.append({
                            "type": "wide_listen",
                            "detail": f"Listening on {lip}:{lport} across all interfaces"
                        })

        if proc_findings:
            findings.append({
                "timestamp": ts,
                "pid": pid,
                "name": name,
                "exe": exe,
                "user": user,
                "findings": proc_findings,
                "connections": [summarize_connection(c) for c in conns]
            })

    return findings

def append_findings(all_findings):
    prev = []
    if os.path.exists(FINDINGS_FILE):
        try:
            with open(FINDINGS_FILE, "r", encoding="utf-8") as f:
                prev = json.load(f)
        except Exception:
            prev = []
    prev.extend(all_findings)
    with open(FINDINGS_FILE, "w", encoding="utf-8") as f:
        json.dump(prev, f, indent=2)

def print_summary(findings):
    print(f"[Cycle] Findings: {len(findings)}")
    by_type = {}
    for f in findings:
        for item in f["findings"]:
            by_type[item["type"]] = by_type.get(item["type"], 0) + 1
    for t, count in sorted(by_type.items(), key=lambda x: (-x[1], x[0])):
        print(f"  - {t}: {count}")

def main():
    print("Initializing baseline and monitors...")
    baseline_paths = load_baseline()
    if not baseline_paths:
        baseline_paths = collect_baseline_paths()
        save_baseline(baseline_paths)
        print(f"Baseline initialized with {len(baseline_paths)} executables")

    blocknets = load_blocklist()
    suspicious_dirs = get_suspicious_dirs()
    print(f"Loaded blocklist networks: {len(blocknets)}")
    print(f"Monitoring every {SCAN_INTERVAL_SECONDS}s. Press Ctrl+C to stop.")

    try:
        while True:
            findings = monitor_cycle(baseline_paths, blocknets, suspicious_dirs)
            if findings:
                append_findings(findings)
            print_summary(findings)
            time.sleep(SCAN_INTERVAL_SECONDS)
    except KeyboardInterrupt:
        print("Stopped.")

if __name__ == "__main__":
    main()

Usage notes:
- Create a blocklist.txt in the same directory if you want IP/CIDR checks (one per line).
- Tune suspicious ports and directories for your environment.
- Pair this with OS logging (process creation, DNS queries, file writes to autorun locations) for stronger detection.

