Product listing API route
pages/api/products/index.ts
import { prisma } from "@/lib/prisma";

export default async function handler(req, res) {
  if (req.method === "GET") {
    const { q, page = "1", limit = "20", category } = req.query;
    const skip = (parseInt(page as string) - 1) * parseInt(limit as string);
    const where: any = { status: "ACTIVE" };
    if (q) where.name = { contains: q as string, mode: "insensitive" };
    if (category) where.category = category as string;
    const [items, count] = await Promise.all([
      prisma.product.findMany({ where, skip, take: parseInt(limit as string), orderBy: { createdAt: "desc" } }),
      prisma.product.count({ where }),
    ]);
    res.json({ items, count });
  } else if (req.method === "POST") {
    // require admin check
    // create product
    const data = req.body;
    const product = await prisma.product.create({ data });
    res.status(201).json(product);
  } else {
    res.status(405).end();
  }
}

Cart and checkout flow (Stripe)
- Client: send cart to server to create a Stripe session
- Server: create session, return URL, redirect client

pages/api/checkout.ts
import Stripe from "stripe";
import { prisma } from "@/lib/prisma";
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY as string);

export default async function handler(req, res) {
  if (req.method !== "POST") return res.status(405).end();
  const { items, currency } = req.body as { items: Array<{ productId: string, quantity: number }>, currency: string };
  const products = await prisma.product.findMany({
    where: { id: { in: items.map(i => i.productId) }, status: "ACTIVE" }
  });

  const line_items = items.map(i => {
    const p = products.find(x => x.id === i.productId)!;
    return {
      quantity: i.quantity,
      price_data: {
        currency,
        product_data: { name: p.name },
        unit_amount: p.price,
      },
    };
  });

  const session = await stripe.checkout.sessions.create({
    mode: "payment",
    payment_method_types: ["card"],
    line_items,
    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/checkout/success?session_id={CHECKOUT_SESSION_ID}`,
    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/cart`,
  });

  res.json({ url: session.url });
}

Stripe webhook to mark orders paid
pages/api/stripe-webhook.ts
import Stripe from "stripe";
import { prisma } from "@/lib/prisma";

export const config = { api: { bodyParser: false } };

export default async function handler(req, res) {
  const stripe = new Stripe(process.env.STRIPE_SECRET_KEY as string);
  const sig = req.headers["stripe-signature"] as string;
  const buf = await (await import("micro")).buffer(req);
  let event;
  try {
    event = stripe.webhooks.constructEvent(buf, sig, process.env.STRIPE_WEBHOOK_SECRET as string);
  } catch {
    return res.status(400).send(`Bad signature`);
  }

  if (event.type === "checkout.session.completed") {
    const session = event.data.object as any;
    await prisma.order.update({
      where: { stripeSessionId: session.id },
      data: { status: "PAID" }
    });
  }
  res.json({ received: true });
}

