#!/usr/bin/env python3
import socket
import ssl
import sys
import time
import argparse
import threading
from datetime import datetime
from urllib.parse import urlparse

MULTICAST_GROUP = ("239.255.255.250", 1900)
SSDP_MSEARCH = "\r\n".join([
    "M-SEARCH * HTTP/1.1",
    "HOST: 239.255.255.250:1900",
    "MAN: \"ssdp:discover\"",
    "MX: 2",
    "ST: ssdp:all",
    "", ""
])

COMMON_PORTS = {
    21:  "FTP",
    22:  "SSH",
    23:  "Telnet",
    80:  "HTTP",
    443: "HTTPS",
    554: "RTSP",
    1900:"SSDP",
    1883:"MQTT",
    8883:"MQTT-TLS",
    5683:"CoAP",
    161: "SNMP"
}

socket.setdefaulttimeout(2.5)

def send_ssdp_discover(timeout=4.0, repeats=2):
    """Broadcast SSDP M-SEARCH and collect responses."""
    responses = []
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
    sock.setsockopt(socket.IPPROTO_IP, socket.IP_MULTICAST_TTL, 2)
    sock.settimeout(timeout)
    try:
        for _ in range(repeats):
            sock.sendto(SSDP_MSEARCH.encode("utf-8"), MULTICAST_GROUP)
        t_end = time.time() + timeout
        while time.time() < t_end:
            try:
                data, addr = sock.recvfrom(65535)
                responses.append((addr[0], parse_ssdp_response(data.decode(errors="ignore"))))
            except socket.timeout:
                break
    finally:
        sock.close()
    # Deduplicate by host
    dedup = {}
    for ip, info in responses:
        if ip not in dedup:
            dedup[ip] = info
    return dedup

def parse_ssdp_response(raw):
    lines = raw.split("\r\n")
    headers = {}
    for line in lines[1:]:
        if ":" in line:
            k, v = line.split(":", 1)
            headers[k.strip().upper()] = v.strip()
    return {
        "SERVER": headers.get("SERVER"),
        "ST": headers.get("ST"),
        "USN": headers.get("USN"),
        "LOCATION": headers.get("LOCATION")
    }

def is_port_open(host, port, timeout=1.5):
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except Exception:
        return False

def grab_http_banner(host, port=80, timeout=2.5):
    try:
        with socket.create_connection((host, port), timeout=timeout) as s:
            req = f"HEAD / HTTP/1.1\r\nHost: {host}\r\nConnection: close\r\n\r\n"
            s.sendall(req.encode("utf-8"))
            data = s.recv(4096).decode(errors="ignore")
        headers = {}
        for line in data.split("\r\n"):
            if ":" in line:
                k, v = line.split(":", 1)
                headers[k.strip().lower()] = v.strip()
        status_line = data.split("\r\n")[0] if data else ""
        return {"status": status_line, "server": headers.get("server"), "powered_by": headers.get("x-powered-by")}
    except Exception:
        return None

def inspect_tls_cert(host, port=443, timeout=3.0):
    try:
        ctx = ssl.create_default_context()
        with socket.create_connection((host, port), timeout=timeout) as sock:
            with ctx.wrap_socket(sock, server_hostname=host) as ssock:
                cert = ssock.getpeercert()
        # Extract key fields
        subject = dict(x[0] for x in cert.get("subject", []))
        issuer  = dict(x[0] for x in cert.get("issuer", []))
        not_after = cert.get("notAfter")
        expires = None
        if not_after:
            expires = datetime.strptime(not_after, "%b %d %H:%M:%S %Y %Z")
        return {
            "subject_cn": subject.get("commonName"),
            "issuer_cn": issuer.get("commonName"),
            "self_signed": subject.get("commonName") == issuer.get("commonName"),
            "expires": expires
        }
    except ssl.SSLError:
        # Likely self-signed or TLS issues
        return {"error": "TLS error"}
    except Exception:
        return None

def scan_host(host):
    findings = {
        "ip": host,
        "open_ports": {},
        "http": None,
        "https_cert": None,
        "ssdp": None,
        "risk": []
    }
    # Port scans
    for port, name in COMMON_PORTS.items():
        if is_port_open(host, port):
            findings["open_ports"][port] = name
    # HTTP banner
    if 80 in findings["open_ports"]:
        findings["http"] = grab_http_banner(host, 80)
        if findings["http"] and not findings["http"].get("server"):
            findings["risk"].append("HTTP exposed with unknown server banner")
        if 443 not in findings["open_ports"]:
            findings["risk"].append("Web admin over plain HTTP, no HTTPS listener")
    # HTTPS cert
    if 443 in findings["open_ports"]:
        cert = inspect_tls_cert(host, 443)
        findings["https_cert"] = cert
        if cert:
            if cert.get("self_signed"):
                findings["risk"].append("HTTPS uses self-signed certificate")
            exp = cert.get("expires")
            if exp and exp < datetime.utcnow():
                findings["risk"].append("TLS certificate expired")
        else:
            findings["risk"].append("HTTPS present but certificate could not be parsed")
    # Service risks
    if 23 in findings["open_ports"]:
        findings["risk"].append("Telnet enabled (unencrypted remote access)")
    if 21 in findings["open_ports"]:
        findings["risk"].append("FTP enabled (unencrypted file service)")
    if 554 in findings["open_ports"]:
        findings["risk"].append("RTSP stream reachable")
    if 1900 in findings["open_ports"]:
        findings["risk"].append("SSDP/UPnP responding")
    if 1883 in findings["open_ports"]:
        findings["risk"].append("MQTT broker reachable without TLS")
    if 5683 in findings["open_ports"]:
        findings["risk"].append("CoAP service reachable")
    if 161 in findings["open_ports"]:
        findings["risk"].append("SNMP service reachable")
    return findings

def advice_for(findings):
    tips = []
    ports = findings["open_ports"]
    # General
    tips.append("Update device firmware to latest release from the vendor")
    tips.append("Use strong, unique passwords and disable default accounts")
    tips.append("Place IoT devices on a separate Wi‑Fi/VLAN from laptops and phones")
    tips.append("Enable WPA2/WPA3 on Wi‑Fi and disable WPS")
    tips.append("Disable remote administration from WAN on the router")
    tips.append("Turn off UPnP on the router and on the device if possible")
    tips.append("Restrict inbound port forwards to only what you truly need")
    tips.append("Enable two‑factor authentication for any cloud account linked to the device")
    # Specific
    if 23 in ports:
        tips.append("Disable Telnet; use SSH only if needed")
    if 21 in ports:
        tips.append("Disable FTP; use SFTP over SSH if file transfer is needed")
    if 80 in ports and 443 not in ports:
        tips.append("Enable HTTPS on the device web interface and redirect HTTP to HTTPS")
    if findings["https_cert"]:
        cert = findings["https_cert"]
        if cert and cert.get("self_signed"):
            tips.append("Install a trusted certificate on the device or use a reverse proxy with TLS")
        exp = cert.get("expires")
        if exp and exp < datetime.utcnow():
            tips.append("Renew the TLS certificate")
    if 1900 in ports:
        tips.append("Turn off UPnP discovery if the device offers that option")
    if 1883 in ports and 443 not in ports and 8883 not in ports:
        tips.append("Use MQTT over TLS (port 8883) and enforce authentication")
    if 161 in ports:
        tips.append("Disable SNMP or lock it down to read‑only with strong credentials and restrict source IPs")
    if 554 in ports:
        tips.append("Require authentication for RTSP streams and avoid exposure to the internet")
    if 5683 in ports:
        tips.append("Require DTLS for CoAP and restrict access to trusted hosts")
    return tips

def resolve_hostname(ip):
    try:
        return socket.gethostbyaddr(ip)[0]
    except Exception:
        return None

def audit_targets(targets):
    results = []
    for host in targets:
        findings = scan_host(host)
        hostname = resolve_hostname(host)
        findings["hostname"] = hostname
        findings["advice"] = advice_for(findings)
        results.append(findings)
    return results

def parse_targets_arg(arg):
    # Simple parser: comma-separated list or CIDR /24
    items = [x.strip() for x in arg.split(",") if x.strip()]
    ips = []
    for item in items:
        if "/" in item:
            base, cidr = item.split("/", 1)
            cidr = int(cidr)
            if cidr != 24:
                print(f"CIDR {cidr} not supported in simple parser; use /24")
                continue
            parts = base.split(".")
            if len(parts) != 4:
                continue
            prefix = ".".join(parts[:3])
            for i in range(1, 255):
                ips.append(f"{prefix}.{i}")
        else:
            ips.append(item)
    return ips

def main():
    parser = argparse.ArgumentParser(description="Smart Home Security Auditor")
    parser.add_argument("--targets", help="Comma-separated IPs or /24 CIDR (e.g., 192.168.1.0/24)")
    parser.add_argument("--ssdp", action="store_true", help="Discover devices via SSDP")
    args = parser.parse_args()

    discovered = {}
    if args.ssdp:
        print("Running SSDP discovery...")
        discovered = send_ssdp_discover(timeout=4.0, repeats=2)
        if discovered:
            print(f"Discovered {len(discovered)} device(s) via SSDP:")
            for ip, info in discovered.items():
                print(f"  {ip} | SERVER={info.get('SERVER')} | ST={info.get('ST')} | LOCATION={info.get('LOCATION')}")
        else:
            print("No SSDP responses")

    targets = []
    if args.targets:
        targets = parse_targets_arg(args.targets)
    else:
        targets = list(discovered.keys())

    if not targets:
        print("No targets specified. Use --ssdp or --targets.")
        sys.exit(0)

    print(f"Auditing {len(targets)} target(s)...")
    results = audit_targets(targets)

    for r in results:
        print("\n==============================")
        print(f"IP: {r['ip']}" + (f"  Hostname: {r['hostname']}" if r['hostname'] else ""))
        if r["open_ports"]:
            print("Open services:")
            for p, name in sorted(r["open_ports"].items()):
                print(f"  {p}/tcp  {name}")
        else:
            print("No common IoT service ports open")
        if r["http"]:
            http = r["http"]
            print(f"HTTP: {http.get('status')}  Server: {http.get('server')}  X-Powered-By: {http.get('powered_by')}")
        if r["https_cert"]:
            cert = r["https_cert"]
            if cert and not cert.get("error"):
                exp = cert.get("expires")
                exp_str = exp.isoformat() if isinstance(exp, datetime) else str(exp)
                print(f"TLS: subject CN={cert.get('subject_cn')} issuer CN={cert.get('issuer_cn')} self_signed={cert.get('self_signed')} expires={exp_str}")
            else:
                print("TLS: parsing issue")
        if r["risk"]:
            print("Risk signals:")
            for x in r["risk"]:
                print(f"  - {x}")
        print("Recommendations:")
        for tip in r["advice"]:
            print(f"  - {tip}")

if __name__ == "__main__":
    main()

How to use:
- Install Python 3.8+.
- Save the script as smart_home_security_auditor.py.
- Optional: run discovery
  - python3 smart_home_security_auditor.py --ssdp
- Audit specific IPs or a /24 range
  - python3 smart_home_security_auditor.py --targets 192.168.1.10,192.168.1.11
  - python3 smart_home_security_auditor.py --targets 192.168.1.0/24
- Review the output and apply the recommendations on devices you own or administer.

Additional hardening ideas:
- Disable unused services on each device.
- Change default usernames if the platform allows it.
- Rotate passwords on a routine schedule.
- Use a firewall on the router to block unsolicited inbound traffic.
- Log device activity and review for anomalies.
- Prefer vendors with regular security updates and transparent advisories.
